import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

// Validation helpers for email or phone input.
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const phoneRegex = /^\+?\d{8,15}$/;

const normalizePhone = (value = '') => value.replace(/[\s\-()]/g, '');

export default function CustomerLogin() {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [formData, setFormData] = useState({
    identifier: '',
    password: '',
  });

  const [errorMessage, setErrorMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleChange = (e) => {
    setErrorMessage('');
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // Check whether the user typed a valid email or a valid phone number.
  const isValidIdentifier = (value) => {
    const cleanValue = value.trim();
    return emailRegex.test(cleanValue) || phoneRegex.test(normalizePhone(cleanValue));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!isValidIdentifier(formData.identifier)) {
      setErrorMessage('Please enter a valid email address or phone number.');
      return;
    }

    if (!formData.password || formData.password.length < 6) {
      setErrorMessage('Please enter a valid password.');
      return;
    }

    try {
      setIsSubmitting(true);
      setErrorMessage('');

      const response = await axiosInstance.post('/api/auth/customer/login', formData);

      // Save auth data into context/local storage through the existing auth layer.
      login(response.data);

      // Customer home page.
      navigate('/tasks');
    } catch (error) {
      const serverMessage =
        error?.response?.data?.message || 'Login failed. Please check your details and try again.';
      setErrorMessage(serverMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#ececec] flex items-center justify-center px-4">
      <div className="w-[390px] min-h-[844px] bg-[#ececec] px-6 pt-6">
        {/* Top status bar */}
        <div className="flex items-center justify-between text-[14px] font-semibold text-black">
          <span>9:41</span>
          <div className="flex items-center gap-2">
            <div className="w-4 h-2 border border-black rounded-sm" />
            <div className="w-5 h-2 border border-black rounded-sm" />
            <div className="w-6 h-3 border border-black rounded-sm" />
          </div>
        </div>

        <div className="mt-20 flex flex-col items-center">
          <div className="w-[120px] h-[120px] rounded-full bg-white shadow-md flex items-center justify-center">
            <span className="text-[18px] font-bold text-[#4f4f4f]">Customer</span>
          </div>

          <h1 className="mt-6 text-[28px] font-bold text-black">Customer Login</h1>
          <p className="mt-2 text-[14px] text-gray-600">Parcel Pickup Scheduler</p>
        </div>

        <form onSubmit={handleSubmit} className="mt-10">
          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Email or Phone Number
            </label>
            <input
              type="text"
              name="identifier"
              placeholder="Enter your email or phone number"
              value={formData.identifier}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Password
            </label>
            <input
              type="password"
              name="password"
              placeholder="Enter your password"
              value={formData.password}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          {errorMessage && (
            <div className="mb-4 rounded-[12px] bg-red-100 px-4 py-3 text-[13px] text-red-700">
              {errorMessage}
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full h-[48px] rounded-[12px] bg-[#bfbfbf] text-white text-[18px] font-semibold disabled:opacity-70"
          >
            {isSubmitting ? 'Signing In...' : 'Log In'}
          </button>
        </form>

        <div className="mt-8">
          <div className="flex items-center justify-center gap-3">
            <div className="h-[1px] flex-1 bg-[#5f5f5f]" />
            <span className="text-[15px] text-black font-medium">Log in with</span>
            <div className="h-[1px] flex-1 bg-[#5f5f5f]" />
          </div>

          <div className="mt-5 flex items-center justify-center gap-6">
            <img src="/facebook.jpeg" alt="Facebook" className="w-[44px] h-[44px] object-contain" />
            <img src="/google.jpeg" alt="Google" className="w-[44px] h-[44px] object-contain" />
            <img src="/email.jpeg" alt="Email" className="w-[44px] h-[44px] object-contain" />
            <img src="/phone.jpeg" alt="Phone" className="w-[44px] h-[44px] object-contain" />
          </div>
        </div>

        <button
          type="button"
          onClick={() => navigate('/register')}
          className="mt-8 w-full text-[15px] text-black underline"
        >
          Create an account
        </button>
      </div>
    </div>
  );
}
